const r = $input.first().json;
const nombre = r.nombre || '';
const texto = 'Holaa ' + nombre + ' 🌿 te queremos recordar que tu paquete de clases vence en 2 semanas (el ' + r.vence_at + ') y aun te quedan ' + r.clases_restantes + ' clase(s). Cuando quieras renovamos para que sigas con tu ritmo 💛';
return [{ json: { telefono: r.telefono, texto } }];

