INSERT INTO bejauha.mensajes_logs (telefono, direccion, agente, texto, intent)
SELECT d->>'telefono', 'out', 'sistema', d->>'texto', 'recordatorio_vencimiento'
FROM (SELECT $1::jsonb AS d) x;

