// Filtramos items que tengan datos validos (n8n emite item vacio cuando Postgres devuelve 0 rows)
const items = $input.all().filter(it => it && it.json && it.json.telefono);
if (items.length === 0) return [];
const lineas = items.map(it => {
  const j = it.json;
  const horas = Math.round(j.horas_pendiente || 48);
  return '• ' + (j.nombre || j.telefono) + ' (+' + j.telefono + ') — ' + horas + 'h sin cerrarse' + (j.resumen ? ': ' + j.resumen : '');
}).join('\n');
const ASESOR = '120363409231703955@g.us';
const texto = '🧹 Auto-cierre de handoffs (≥ 48h pendientes):\n' + lineas + '\n\nEl bot vuelve a atender a estos clientes si vuelven a escribir. Si seguían en venta abierta, retómenla manualmente.';
return [{ json: { asesor_whatsapp: ASESOR, alerta_text: texto } }];
